714: // ValidateCronJobCreate validates a CronJob on creation and returns an ErrorList with any errors.
715: func ValidateCronJobCreate(cronJob *batch.CronJob, opts apivalidation.PodValidationOptions) field.ErrorList {
716: 	// CronJobs and rcs have the same name validation
717: 	allErrs := apivalidation.ValidateObjectMeta(&cronJob.ObjectMeta, true, apivalidation.ValidateReplicationControllerName, field.NewPath("metadata"))
718: 	allErrs = append(allErrs, validateCronJobSpec(&cronJob.Spec, nil, field.NewPath("spec"), opts)...)
719: 	if len(cronJob.ObjectMeta.Name) > apimachineryvalidation.DNS1035LabelMaxLength-11 {
720: 		// The cronjob controller appends a 11-character suffix to the cronjob (`-$TIMESTAMP`) when
721: 		// creating a job. The job name length limit is 63 characters.
722: 		// Therefore cronjob names must have length <= 63-11=52. If we don't validate this here,
723: 		// then job creation will fail later.
724: 		allErrs = append(allErrs, field.Invalid(field.NewPath("metadata").Child("name"), cronJob.ObjectMeta.Name, "must be no more than 52 characters"))
725: 	}
726: 	return allErrs
727: }
