776: func validateConcurrencyPolicy(concurrencyPolicy *batch.ConcurrencyPolicy, fldPath *field.Path) field.ErrorList {
777: 	allErrs := field.ErrorList{}
778: 	switch *concurrencyPolicy {
779: 	case batch.AllowConcurrent, batch.ForbidConcurrent, batch.ReplaceConcurrent:
